/**
 * Types for the async job execution pipeline.
 *
 * Ported from Python SDK `analyses/jobs.py`.
 */

// ---------------------------------------------------------------------------
// JobStatus enum
// ---------------------------------------------------------------------------

/**
 * Job status values.
 *
 * The API returns PascalCase status strings. The historical typo
 * 'Succeded' (single 'e') is normalised to 'succeeded'.
 */
export const JobStatus = {
  Pending: 'pending',
  Running: 'running',
  Succeeded: 'succeeded',
  Failed: 'failed',
  Unknown: 'unknown',
} as const

export type JobStatus = (typeof JobStatus)[keyof typeof JobStatus]

/** Map raw API status strings to normalised JobStatus values. */
const RAW_TO_STATUS: Record<string, JobStatus> = {
  Pending: JobStatus.Pending,
  Running: JobStatus.Running,
  Succeeded: JobStatus.Succeeded,
  Succeded: JobStatus.Succeeded, // normalise historical API typo
  Failed: JobStatus.Failed,
}

/**
 * Parse a raw status string from the API into a JobStatus.
 *
 * Handles the historical 'Succeded' (single 'e') typo by normalising
 * it to `JobStatus.Succeeded`.
 *
 * @param raw - The raw PascalCase status string from the API.
 * @returns The normalised JobStatus value.
 *
 * @example
 * ```ts
 * parseJobStatus('Succeeded') // 'succeeded'
 * parseJobStatus('Succeded')  // 'succeeded' (normalised typo)
 * parseJobStatus('Unknown')   // 'unknown'
 * ```
 */
export function parseJobStatus(raw: string): JobStatus {
  return RAW_TO_STATUS[raw] ?? JobStatus.Unknown
}

/** Terminal job statuses (no further state transitions). */
export const TERMINAL_STATUSES: ReadonlySet<JobStatus> = new Set([
  JobStatus.Succeeded,
  JobStatus.Failed,
])

// ---------------------------------------------------------------------------
// Job
// ---------------------------------------------------------------------------

/** Immutable snapshot of a job returned by the API. */
export interface Job {
  readonly jobId: string
  readonly modelName: string
  readonly status: JobStatus
  readonly requestedAt: string
  readonly startedAt?: string
  readonly finishedAt?: string
  readonly resultsUrl?: string
  readonly error?: string
}

/**
 * Build a Job from an API response dict (camelCase keys).
 *
 * Handles both `status` (submit response) and `jobStatus`
 * (poll response) field names, and normalises the 'Succeded'
 * typo to `JobStatus.Succeeded`.
 *
 * @param data - The raw API response object with camelCase keys.
 * @returns An immutable Job snapshot.
 *
 * @example
 * ```ts
 * const job = jobFromResponse({
 *   jobId: 'abc-123',
 *   modelName: 'wind-speed',
 *   status: 'Succeeded',
 *   requestedAt: '2025-01-01T00:00:00Z',
 * })
 * // job.status === 'succeeded'
 * ```
 */
/**
 * Narrow a possibly-unknown field to a string. Returns `undefined` for any
 * non-string value (including null, numbers, objects). Used to harden
 * `jobFromResponse` against shape drift in API responses.
 */
function asStringOrUndefined(v: unknown): string | undefined {
  return typeof v === 'string' ? v : undefined
}

export function jobFromResponse(data: Record<string, unknown>): Job {
  // Defensive narrowing — Python uses Pydantic `model_validate` here which
  // would raise on unexpected types. TS uses runtime typeof checks so we
  // get a coherent Job shape even when the API drifts (e.g. returns a
  // numeric `jobId` or a null `requestedAt`).
  const jobId = asStringOrUndefined(data.jobId)
  if (!jobId) {
    throw new Error(
      `jobFromResponse: missing or non-string jobId (got ${typeof data.jobId})`,
    )
  }
  const rawStatus =
    asStringOrUndefined(data.jobStatus) ?? asStringOrUndefined(data.status) ?? 'Unknown'
  return {
    jobId,
    modelName: asStringOrUndefined(data.modelName) ?? '',
    status: parseJobStatus(rawStatus),
    requestedAt: asStringOrUndefined(data.requestedAt) ?? '',
    startedAt: asStringOrUndefined(data.startedAt),
    finishedAt: asStringOrUndefined(data.finishedAt),
    resultsUrl: asStringOrUndefined(data.results),
    error: asStringOrUndefined(data.error),
  }
}

// ---------------------------------------------------------------------------
// DownloadResult
// ---------------------------------------------------------------------------

/** Result of downloading job output from the presigned URL. */
export interface DownloadResult {
  readonly content: Uint8Array
  readonly presignedUrl: string
  readonly jobId: string
  readonly contentType: string
}

// ---------------------------------------------------------------------------
// IJobsService interface (for DI / testing)
// ---------------------------------------------------------------------------

/**
 * Callback fired on each poll iteration.
 *
 * @param job - Current job snapshot
 * @param attempt - Zero-based attempt index
 * @param elapsed - Seconds elapsed since polling started
 * @param nextDelay - Seconds until next poll (0 for terminal states)
 * @returns Return `false` to stop polling early; any other value continues.
 */
export type OnPollCallback = (
  job: Job,
  attempt: number,
  elapsed: number,
  nextDelay: number,
  // biome-ignore lint/suspicious/noConfusingVoidType: void is idiomatic for callbacks that return nothing
) => boolean | void | Promise<boolean | void>

/** Interface for dependency injection and testing. */
export interface IJobsService {
  submit(
    analysisType: string,
    payload: Record<string, unknown>,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<Job>
  getStatus(jobId: string): Promise<Job>
  waitForCompletion(
    jobId: string,
    opts?: { timeout?: number; onPoll?: OnPollCallback },
  ): Promise<Job>
  downloadResults(jobId: string, opts?: { job?: Job }): Promise<DownloadResult>
  decompress(content: Uint8Array): Record<string, unknown>
}
